var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"그로니아 국경지대 \\n관리국 관할 샤레이드 입국 관리소 주변, 대기 난민 거주구역.","ENG":"Gronia national border\\nThe waiting refugee camp near the Administration's Charade immigration center","TWN":"格羅尼亞邊境地區\\n管理局管轄的查雷德出入境管理所附近，難民等待居住區。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"네? 1년…… 이요?","JPN":"はい？　1年……ですか？","ENG":"Sorry? A... year?","TWN":"什麼？1年……嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_F","text":{"KOREA":"입국 심사는 그보다 오래 걸리는 경우가 보통입니다.","JPN":"入国審査はそれ以上長くかかるのが普通です。","ENG":"The immigration screening process usually takes longer than that.","TWN":"入境審查本來就需要比較長的時間。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_F","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_F","text":{"KOREA":"침식 증후군 검사나, 난민 신청에 필요한 행정 절차도 그렇고…….","JPN":"侵食症候群検査や、難民申請に必要な行政手続もそうですし……","ENG":"You have to get tested for Corruption Syndrome, and you also have to get all the documents you need for the refugee visa.","TWN":"侵蝕症候群檢驗，或是難民申請要走的行政程序也是一樣……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_F","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_F","text":{"KOREA":"여길 넘어가려는 난민들은 수도 없이 많으니까요.","JPN":"ここを越えようとする難民は数え切れないほど多いですからね。","ENG":"Countless refugees come here to cross the border.","TWN":"畢竟有數不清的難民都等著要穿越國界。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_F","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"다른 방법은…… 없는 걸까요?","JPN":"他の方法は……ありませんか？","ENG":"Isn't there any other way?","TWN":"沒有……其他方法嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"신분증이나 과거 활동을 증명하는 경력서가 있으면 좀 더 단축될 수는 있다고 알고 있네만.","JPN":"身分証明書や過去の活動を証明する経歴書があれば、もう少し短縮できると聞いたんじゃが。","ENG":"If you have an identification card or something else that can prove your past history, then you may be able to shorten your waiting period.","TWN":"我聽說只要有身分證，或是可以證明過去活動的履歷，就可以縮短申請時間。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"자네, 신분증은 가지고 있나?","JPN":"君、身分証明書は持っているかね。","ENG":"Do you have an identification card?","TWN":"你有身分證嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아.","JPN":"あっ。","ENG":"Ah.","TWN":"嗯…"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"……아뇨.","JPN":"……いいえ。","ENG":"… No.","TWN":"……我沒有。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"목숨을 걸고 여기까지 오더라도, 진짜 남은 문제는 심사장의 까다로운 입국 절차라네.","JPN":"命がけでここまで来ても、真の問題は審査施設の厳しい入国手続きじゃ。","ENG":"Even if you make it all the way here alive, the real problem remains and it's the complicated immigration process.","TWN":"好不容易拚了命來到這裡，結果最大的難題卻是繁瑣的入境申請。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"수가 많은데다 이상한 사상에 물든 자들이 넘어갈 수도 있으니, 이해가 안 되는 건 아니지.","JPN":"数が多いうえに、変な思想に染まった者が入国することもあり得るから、理解できないことはない。","ENG":"It's understandable, given the number of people who want to cross the border, and some of them can be too dangerous to be let in.","TWN":"這個世界就是少數服從多數，即使是不合理的事，但世界就是這麼運作的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"유감이지만, 우리로선 선택의 여지가 없다네.","JPN":"残念じゃが、ワシらとしては選択の余地がないんじゃ。","ENG":"It's a shame, but we have no choice.","TWN":"雖然很遺憾，但我們沒有選擇的餘地。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"그래도 이곳 거주구역은 정부군의 직접적인 보호를 받고 있어서 비교적 안전한 편이야.","JPN":"じゃが、ここの居住区域は政府軍から直接保護されているし、比較的安全なほうじゃ。","ENG":"At least this camp is under the direct protection of the government. It's fairly safe.","TWN":"不過這裡的住宅區是直接受到政府軍的保護，起碼安全一點囉。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"알겠습니다. 여기까지 태워주셔서 감사해요.","JPN":"わかりました。ここまで乗せてくださって、ありがとうございました。","ENG":"I see. Thank you for giving me a ride.","TWN":"好的，謝謝您載我到這裡。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"당연히 내가 더 고맙지. 그때 거기서 카운터를 만나게 될 줄 누가 알았겠나.","JPN":"いやいや、ワシのほうこそ感謝しとるよ。あの時、まさかカウンターに会えるなんて思ってなかったからのう。","ENG":"No, thank you. Who knew I'd be saved by a Counter like that?","TWN":"我才應該謝謝你呢！沒想到竟然會在那個時候遇到制裁者。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"거기, 잠깐.","JPN":"そこの君、ちょっと。","ENG":"Hey, wait.","TWN":"你說什麼？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"방금 카운터라고 했나요?","JPN":"今カウンターと言いましたか？","ENG":"Did you just say she's a Counter?","TWN":"你說遇到制裁者？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"혹시 여러분 중에 카운터가 있습니까?","JPN":"みなさんの中にカウンターはいますか？","ENG":"Are any of you a Counter?","TWN":"你們當中有制裁者嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"그렇습니다. 이 아가씨가 카운터입니다만.","JPN":"はい。このお嬢ちゃんがカウンターです。","ENG":"Yes. This lady here is one.","TWN":"對啊，這位小姐就是制裁者。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"그렇다면 당신은 이쪽으로 오세요. 지금 바로 입국심사를 도와드리겠습니다.","JPN":"それなら、あなたはこちらへどうぞ。今すぐ入国審査を進めます。","ENG":"Then, you can come this way. I'll help you with your screening process right away.","TWN":"那請你跟我來，我來幫你申請入境許可。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"워치를 가진 카운터라면 망명 절차를 빠르게 처리해 드릴 수 있어요.","JPN":"ウォッチを持つカウンターなら、亡命手続きをすぐに処理できますよ。","ENG":"If you're a Counter with a Watch, you can enter the country more quickly.","TWN":"制裁者可以省略那些繁複的流程。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"저, 정말인가요?","JPN":"ほ、本当ですか？","ENG":"R-really?","TWN":"真…真的嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그렇지만…… 저 혼자……","JPN":"でも……私一人で……","ENG":"But... I shouldn't go alone...","TWN":"可是……只有我……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"그런 표정 짓지 말게. 오히려 잘된 일이야.","JPN":"そんな顔しないでおくれ。むしろよかったじゃないか。","ENG":"No, don't be sad. This is good for you.","TWN":"你不用這樣，這是好事啊。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"어서 가서 자네 동생들을 만나야지.","JPN":"早く行って君の妹たちに会いなさい。","ENG":"You can go meet your sisters now.","TWN":"你快去和妹妹們團圓！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"언니, 잘 가! 고마웠어!","JPN":"お姉ちゃん、さよなら！　ありがとう！","ENG":"Lucid, goodbye! Thank you for everything!","TWN":"姊姊再見～謝謝你。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"……응. 고마워, 얘들아.","JPN":"……うん。ありがとう、みんな。","ENG":"... Okay. Thank you, guys.","TWN":"……嗯，謝謝你們。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"그럼 이쪽으로 가시죠.","JPN":"それではこちらへ。","ENG":"Now, please come this way.","TWN":"請跟我來吧。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"최근 이곳을 찾아오는 난민들이 부쩍 늘었습니다.","JPN":"最近ここを訪れる難民がどんどん増えてきました。","ENG":"Recently, more refugees have been coming to the border every day.","TWN":"最近有越來越多的難民到我們這裡來，"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"그만큼 살기 힘들어졌다는 반증이겠죠.","JPN":"それだけ、グロニアが暮らしにくくなったということでしょう。","ENG":"Things must have been so tough where they came from.","TWN":"這也就表示生活越來越不容易了吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"그럼 지금부터 카운터라는 걸 증명해줄 서류를 작성하겠습니다.","JPN":"それでは、カウンターであることを証明する書類を作成します。","ENG":"Now, let's fill out this document to prove you're a Counter.","TWN":"接下來我們需要完成一份制裁者證明文件，"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"당신은 어떤 능력을 갖고 계시죠?","JPN":"あなたはどんな能力を持っていますか？","ENG":"What kind of ability do you have?","TWN":"請問你有什麼樣的能力呢？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"저도, 뭐라고 잘 설명은 못하겠지만…… 다른 사람에게 제 정신을 연결할 수 있는 것 같아요.","JPN":"自分でもうまく説明できませんが……他の人に私の精神を繋ぐことができるみたいです。","ENG":"I... I don't know how to explain it, but I think I can connect to other people's minds.","TWN":"有點難解釋……應該就是我的思想可以連結到別人的大腦。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"흐음, 다른 사람의 정신을 조종할 수도 있는 겁니까?","JPN":"ふむ、他の人の精神を操ることもできるのですか？","ENG":"Hm, then can you control their minds as well?","TWN":"嗯嗯，就是可以控制別人的思想對吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그, 그 정도까진 아니지만…… 그 사람의 기억을 엿보거나 꿈을 공유할 수 있어요.","JPN":"そ、そこまではできませんが……その人の記憶を覗いたり、夢を共有することができます。","ENG":"I-I don't think so, but at least I can take a peek at their memories and share dreams with them.","TWN":"不至於到控制的程度……而是我可以看到他的回憶，或是分享夢境。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그게 항상 제 의사대로 되진 않지만요.","JPN":"でも、いつも私の意思どおりになるわけではありません。","ENG":"I can't always do that as freely as I want, though.","TWN":"雖然不是每次都成功。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그리고…… 침식체와 정신을 연결하면, 침식체가 절 도와주기도 하고요.","JPN":"あと……侵食体と精神を繋ぐと、侵食体が私を助けてくれることもあります。","ENG":"And... I can also connect with C.O.s to get help.","TWN":"還有……和侵蝕體連結時，侵蝕體就會幫助我。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"그거 신기하군요. 침식체를 조종하다니, 확실히 전례가 없는 케이스네요.","JPN":"それは不思議ですね。侵食体を操るなんて、確かに前例のないケースですね。","ENG":"How marvelous! Controlling C.O.s? This is unprecedented.","TWN":"這麼神奇！竟然可以控制侵蝕體，我還是第一次聽到呢！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"마치, 축복 같은 능력입니다.","JPN":"まるで、祝福のような能力です。","ENG":"It's like a blessing.","TWN":"這根本是蒙福的超能力！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그런…… 가요.","JPN":"そんな……ことはありません。","ENG":"... Is it?","TWN":"是……這樣嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"이걸 목에 차보시겠습니까? CRF측정을 도와줄 거예요.","JPN":"これを首につけてみてください。CRF測定ができます。","ENG":"Could you wear this around your neck? It helps measure your CRF.","TWN":"麻煩幫我把這個戴在脖子上，我要幫你測量CRF。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아, 네.","JPN":"あ、はい。","ENG":"Oh, okay.","TWN":"喔，好的。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"이렇게 하면 되는 건가요?","JPN":"こんな感じですか？","ENG":"Like this?","TWN":"這樣可以嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"으윽?!","JPN":"ううっ！？","ENG":"Ugh!","TWN":"呃嗚？！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_QM","text":{"KOREA":"그런 축복을 받았으면, 평생 감사를 해도 모자랄 판에 말이죠.","JPN":"そんな祝福を受けたのなら、感謝してもしきれないものなのに。","ENG":"You're so blessed. You should have been grateful for those who gave you that blessing for the rest of your life.","TWN":"這麼蒙福，不是應該一輩子心懷感恩嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_QM","text":{"KOREA":"왜 배신을 하는 겁니까?","JPN":"なぜ裏切るのですか？","ENG":"Why did you betray them?","TWN":"為什麼要當叛徒呢？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_QM","text":{"KOREA":"잘 도망쳤다고 생각했겠지만, 결국 오게 되는 곳은 뻔하죠.","JPN":"うまく逃げたと思ったのでしょうが、結局たどり着く先は決まっています。","ENG":"You thought you'd escaped. But there's only one place you can really go.","TWN":"你以為你逃得了嗎？逃了半天結果還不是一樣！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_QM","text":{"KOREA":"이제 집으로 돌아갈 시간이에요.","JPN":"もう家に帰る時間です。","ENG":"Now, it's time to go back home.","TWN":"是時候回家囉。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아, 안…… 돼…….","JPN":"ダ、ダ……メ……","ENG":"Ah, no...","TWN":"不…不……要……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};